// 判断 fireworkMusic 是否有真实音源
function hasSecondMusic() {
    var fm = document.getElementById('fireworkMusic');
    if (!fm) return false;
    var src = fm.querySelector('source');
    if (!src) return false;
    var val = src.getAttribute('src') || '';
    // 只有 data:audio 开头或有效 URL 才算有音源
    return val.length > 10 && (val.startsWith('data:audio') || val.startsWith('http'));
}

// 淡入音频（返回 Promise）
function fadeInAudio(audioEl, duration, targetVol) {
    return new Promise(function(resolve, reject) {
        if (!audioEl) { reject('no element'); return; }
        targetVol = typeof targetVol === 'number' ? targetVol : getUserVolume();
        audioEl.volume = 0;
        audioEl.play().then(function() {
            var step = 50;
            var delta = targetVol / (duration / step);
            var timer = setInterval(function() {
                if (audioEl.volume + delta >= targetVol) {
                    audioEl.volume = targetVol;
                    clearInterval(timer);
                    resolve();
                } else {
                    audioEl.volume = Math.min(audioEl.volume + delta, targetVol);
                }
            }, step);
        }).catch(function(e) {
            audioEl.volume = targetVol; // 恢复音量
            reject(e);
        });
    });
}

// 淡出音频（返回 Promise）
function fadeOutAudio(audioEl, duration) {
    return new Promise(function(resolve) {
        if (!audioEl || audioEl.paused) { resolve(); return; }
        var startVol = audioEl.volume;
        if (startVol <= 0) { audioEl.pause(); resolve(); return; }
        var step = 50;
        var delta = startVol / (duration / step);
        var timer = setInterval(function() {
            if (audioEl.volume - delta <= 0) {
                audioEl.volume = 0;
                audioEl.pause();
                clearInterval(timer);
                resolve();
            } else {
                audioEl.volume = Math.max(audioEl.volume - delta, 0);
            }
        }, step);
    });
}

// 标记当前正在播放哪首音乐: 'bg' | 'report' | null
var _currentTrack = null;

// 页面加载后2秒淡入自动播放第一首音乐
window.addEventListener('load', function() {
    if (!hasLoadedReportData()) return;
    setTimeout(function() {
        fadeInAudio(bgMusic, 2000, getUserVolume()).then(function() {
            isMusicPlaying = true;
            _currentTrack = 'bg';
            if (musicIcon) musicIcon.textContent = '🔊';
        }).catch(function() {
            // 自动播放被浏览器阻止，等待用户首次交互后再播放
            isMusicPlaying = false;
            _currentTrack = null;
            if (musicIcon) musicIcon.textContent = '🔇';
            function onFirstInteraction() {
                document.removeEventListener('click', onFirstInteraction, true);
                document.removeEventListener('touchstart', onFirstInteraction, true);
                if (!isMusicPlaying && _currentTrack === null) {
                    bgMusic.volume = getUserVolume();
                    bgMusic.play().then(function() {
                        isMusicPlaying = true;
                        _currentTrack = 'bg';
                        if (musicIcon) musicIcon.textContent = '🔊';
                    }).catch(function() {});
                }
            }
            document.addEventListener('click', onFirstInteraction, true);
            document.addEventListener('touchstart', onFirstInteraction, true);
        });
    }, 2000);
});

// === 视频/图片处理工具函数 ===
function isVideoUrl(str) {
    if (!str) return false;
    const s = String(str).trim();
    if (/^data:video\//i.test(s)) return true;
    return s.match(/\.(mp4|webm|mov)(\?.*)?$/i) !== null;
}


function getMediaHtml(url, alt, extraClass, onerrorFallback) {
    alt = alt || '';
    extraClass = extraClass || '';
    onerrorFallback = onerrorFallback || '';
    // 转义URL中的特殊字符，防止破坏HTML结构
    const safeUrl = String(url || '').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
    const safeAlt = String(alt || '').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
    
    if (isVideoUrl(url)) {
        return '<video src="' + safeUrl + '" class="' + extraClass + '" style="max-width:100%; max-height:100%; object-fit:contain;" controls muted playsinline preload="metadata"></video>';
    } else {
        const fallback = onerrorFallback || "this.src='https://picsum.photos/400/300?random='+Math.random()";
        return '<img src="' + safeUrl + '" alt="' + safeAlt + '" class="' + extraClass + '" onerror="' + fallback + '">';
    }
}

function genIsUrl(str) {
    if (!str) return false;
    const s = String(str).trim();
    if (/^https?:\/\//i.test(s)) return true;
    if (/\.(jpg|jpeg|png|gif|webp|bmp|mp4|webm|mov)(\?.*)?$/i.test(s)) return true;
    if (/^data:(image|video)\//i.test(s)) return true;
    return false;
}


function applyAudioSource(audioId, dataUrl) {
    const audio = document.getElementById(audioId);
    if (!audio) return;
    let source = audio.querySelector('source');
    if (!source) {
        source = document.createElement('source');
        source.type = 'audio/mpeg';
        audio.appendChild(source);
    }
    source.src = dataUrl || '';
    audio.load();
}


function getAudioSource(audioId) {
    const audio = document.getElementById(audioId);
    if (!audio) return '';
    const source = audio.querySelector('source');
    return source ? (source.getAttribute('src') || '') : '';
}





// ============================================================
// data-processor.js - 数据处理模块 (DataProcessor)
// Excel 解析、数据规范化、统计计算、数据注入
// ============================================================

function normalizeWeeklyPhotos(input) {
    const normalized = createEmptyWeeklyPhotos();
    if (!input || typeof input !== 'object') return normalized;
    Object.keys(normalized).forEach(function(key) {
        if (Array.isArray(input[key])) normalized[key] = input[key].slice();
    });
    return normalized;
}

function hasLoadedReportData() {
    return Array.isArray(DB) && DB.length > 0;
}

function genSmartParseInt(text) {
    if (text === null || text === undefined) return 0;
    const match = String(text).trim().match(/(\d+)/);
    return match ? parseInt(match[1], 10) : 0;
}


function normalizeCellText(value) {
    if (value === null || value === undefined) return '';
    if (typeof value === 'string') return value.trim();
    if (typeof value === 'number' || typeof value === 'boolean') return String(value).trim();
    if (typeof value === 'object') {
        if (typeof value.text === 'string') return value.text.trim();
        if (typeof value.w === 'string') return value.w.trim();
        if (value.v !== undefined && value.v !== null) return String(value.v).trim();
    }
    return String(value).trim();
}

function normalizeAssetKey(input) {
    let s = normalizeCellText(input);
    if (!s) return '';
    s = s.replace(/^file:\/*/i, '');
    s = s.replace(/\\/g, '/');
    s = s.split('#')[0].split('?')[0];
    s = s.replace(/^[A-Za-z]:\//, '');
    s = s.replace(/^\.\/+/, '');
    s = s.replace(/^\/+/, '');
    try { s = decodeURIComponent(s); } catch (e) {}
    return s.toLowerCase();
}

function getFileNameFromPath(path) {
    const normalized = normalizeAssetKey(path);
    if (!normalized) return '';
    const parts = normalized.split('/').filter(Boolean);
    return parts.length ? parts[parts.length - 1] : normalized;
}

function getFileStem(name) {
    const fileName = normalizeCellText(name);
    if (!fileName) return '';
    const idx = fileName.lastIndexOf('.');
    return idx > 0 ? fileName.slice(0, idx) : fileName;
}

function buildAssetLookupKeys(input) {
    const keys = [];
    const normalized = normalizeAssetKey(input);
    if (normalized) keys.push(normalized);
    const fileName = getFileNameFromPath(normalized);
    if (fileName) keys.push(fileName);
    const stem = getFileStem(fileName);
    if (stem) keys.push(stem);
    if (normalized) {
        const parts = normalized.split('/').filter(Boolean);
        if (parts.length >= 2) keys.push(parts.slice(-2).join('/'));
    }
    return Array.from(new Set(keys.filter(Boolean)));
}

function addUploadedImageToMap(imageMap, refPath, dataUrl) {
    const keys = buildAssetLookupKeys(refPath);
    keys.forEach(function(key) {
        if (!imageMap.has(key)) imageMap.set(key, dataUrl);
    });
}

function getHyperlinkTarget(sheet, excelRow, colIndex) {
    if (!sheet || !window.XLSX) return '';
    const addr = XLSX.utils.encode_cell({ r: excelRow - 1, c: colIndex - 1 });
    const cell = sheet[addr];
    if (cell && cell.l && typeof cell.l.Target === 'string') {
        return cell.l.Target.trim();
    }
    return '';
}

function getCellMediaRef(sheet, excelRow, colIndex, fallbackValue) {
    const link = getHyperlinkTarget(sheet, excelRow, colIndex);
    if (link) return link;
    return normalizeCellText(fallbackValue);
}

function resolveMediaRefFromUploads(ref, counters) {
    const val = normalizeCellText(ref);
    if (!val) return '';
    if (/^data:(image|video|audio)\//i.test(val)) return val;
    const map = GENERATOR_STATE.uploadedImageMap;
    if (map && typeof map.get === 'function') {
        const keys = buildAssetLookupKeys(val);
        for (let i = 0; i < keys.length; i++) {
            const mapped = map.get(keys[i]);
            if (mapped) {
                if (mapped !== val) counters.replaced++;
                return mapped;
            }
        }
    }
    const isHttp = /^https?:\/\//i.test(val);
    if (!isHttp && genIsUrl(val)) counters.unresolved++;
    return val;
}

function hydrateDbMediaFromUploadedImages(dbData) {
    const counters = { replaced: 0, unresolved: 0 };
    if (!Array.isArray(dbData) || dbData.length === 0) return counters;

    dbData.forEach(function(user) {
        if (!user || typeof user !== 'object') return;

        if (user.imgs && typeof user.imgs === 'object') {
            Object.keys(user.imgs).forEach(function(k) {
                user.imgs[k] = resolveMediaRefFromUploads(user.imgs[k], counters);
            });
        }

        if (user.commonData && typeof user.commonData === 'object') {
            ['ipPhoto', 'memoryPhoto', 'groupPhoto'].forEach(function(field) {
                if (user.commonData[field]) {
                    user.commonData[field] = resolveMediaRefFromUploads(user.commonData[field], counters);
                }
            });
        }

        if (user.deptData && typeof user.deptData === 'object') {
            Object.keys(user.deptData).forEach(function(deptName) {
                const dept = user.deptData[deptName];
                if (!dept || !Array.isArray(dept.images)) return;
                dept.images.forEach(function(img) {
                    if (!img || !img.url) return;
                    img.url = resolveMediaRefFromUploads(img.url, counters);
                });
            });
        }
    });

    return counters;
}


function detectDeptByPath(path) {
    const normalized = String(path || '').replace(/\\/g, '/').toLowerCase();
    for (let i = 0; i < PHOTO_DEPT_RULES.length; i++) {
        const key = PHOTO_DEPT_RULES[i].keyword.toLowerCase();
        if (
            normalized.includes('/' + key + '/') ||
            normalized.includes(key + '/') ||
            normalized.endsWith('/' + key) ||
            normalized.includes('/' + key + '_')
        ) {
            return PHOTO_DEPT_RULES[i].dept;
        }
    }
    return null;
}

function calculateGlobalStats(rawData) {
    const deptStatsDist = {};
    Object.keys(DEPT_CONTENT_CONFIG).forEach(function(deptName) {
        deptStatsDist[deptName] = {
            stats1: rawData.map(function(u) { return (u.deptData[deptName] && u.deptData[deptName].stats1) || 0; }).sort(function(a, b) { return a - b; }),
            stats2: rawData.map(function(u) {
                const val = u.deptData[deptName] && u.deptData[deptName].stats2;
                return typeof val === 'number' ? val : 0;
            }).sort(function(a, b) { return a - b; })
        };
    });

    const activityDist = rawData.map(function(u) { return (u.stats && u.stats.activityCount) || 0; }).sort(function(a, b) { return a - b; });
    const ipMap = {};
    const kwMap = {};

    rawData.forEach(function(u) {
        if (u.ip) {
            const ipKey = String(u.ip).trim();
            if (!ipMap[ipKey]) ipMap[ipKey] = [];
            ipMap[ipKey].push(u.name);
        }
        (u.keywords || []).forEach(function(k) {
            const key = String(k).trim();
            if (!key) return;
            if (!kwMap[key]) kwMap[key] = [];
            kwMap[key].push(u.name);
        });
    });

    return rawData.map(function(u) {
        const finalU = Object.assign({}, u, { analysis: {} });
        const actVal = (u.stats && u.stats.activityCount) || 0;
        const actLess = activityDist.filter(function(v) { return v < actVal; }).length;
        finalU.analysis.activityPercent = activityDist.length > 1 ? Math.floor((actLess / activityDist.length) * 100) : 100;
        finalU.analysis.deptStats = {};

        Object.keys(DEPT_CONTENT_CONFIG).forEach(function(deptName) {
            const s1 = (u.deptData[deptName] && u.deptData[deptName].stats1) || 0;
            const s2 = (u.deptData[deptName] && u.deptData[deptName].stats2) || 0;
            const dist1 = deptStatsDist[deptName].stats1;
            const dist2 = deptStatsDist[deptName].stats2;
            finalU.analysis.deptStats[deptName] = {
                stats1Percent: dist1.length > 1 ? Math.floor((dist1.filter(function(v) { return v < s1; }).length / dist1.length) * 100) : 100,
                stats2Percent: dist2.length > 1 ? Math.floor((dist2.filter(function(v) { return v < s2; }).length / dist2.length) * 100) : 100
            };
        });

        finalU.analysis.sameIp = (ipMap[String(u.ip || '').trim()] || []).filter(function(name) { return name !== u.name; });
        finalU.analysis.sameKw = {};
        (u.keywords || []).forEach(function(k) {
            const key = String(k).trim();
            finalU.analysis.sameKw[key] = (kwMap[key] || []).filter(function(name) { return name !== u.name; }).length;
        });
        return finalU;
    });
}

function isMarkedChoice(value) {
    const v = normalizeCellText(value).toLowerCase();
    return !!v && ['0', 'false', 'no', '否', '未选', 'null', 'undefined', 'nan', '(空)', '空'].indexOf(v) === -1;
}

async function parseExcelFile(file) {
    if (!window.XLSX) throw new Error('SheetJS 未加载');
    const workbook = XLSX.read(await file.arrayBuffer(), { type: 'array' });
    const firstSheet = workbook.SheetNames[0];
    if (!firstSheet) throw new Error('Excel 不包含工作表');
    const sheet = workbook.Sheets[firstSheet];
    const rows = XLSX.utils.sheet_to_json(sheet, { header: 1, defval: '' });
    const rawData = [];

    for (let idx = 1; idx < rows.length; idx++) {
        const excelRow = idx + 1;
        const rowArray = rows[idx] || [];
        const rowData = {};
        for (let col = 0; col < rowArray.length; col++) rowData[col + 1] = normalizeCellText(rowArray[col]);

        const name = normalizeCellText(rowData[7]);
        if (!name) continue;

        const seniorityNum = normalizeCellText(rowData[8]);
        const joinTime = SENIORITY_MAP[seniorityNum] || ('未知 (' + (seniorityNum || '空') + ')');
        const depts = [];
        Object.keys(DEPT_COL_MAP).forEach(function(colNum) {
            const val = normalizeCellText(rowData[parseInt(colNum, 10)]);
            if (val === '1') depts.push(DEPT_COL_MAP[colNum]);
        });

        const activityRaw = normalizeCellText(rowData[COMMON_CONFIG.activityCol]);
        const activityCountNum = genSmartParseInt(activityRaw);
        // 根据活动次数计算活跃等级 (1-4级)
        let activityLevel = 0;
        if (activityCountNum > 0) {
            if (activityCountNum <= 2) activityLevel = 1;
            else if (activityCountNum <= 5) activityLevel = 2;
            else if (activityCountNum <= 10) activityLevel = 3;
            else activityLevel = 4;
        }
        const activityCount = activityCountNum;

        const user = {
            id: idx + 1,
            name: name,
            joinTime: joinTime,
            depts: depts,
            stats: {
                activityRaw: activityRaw,
                activityLevel: activityLevel,
                activityCount: activityCount
            },
            raw: {},
            imgs: {},
            deptData: {},
            commonData: {},
            ip: '',
            keywords: [],
            keywordReason: ''
        };

        Object.keys(rowData).forEach(function(colNum) {
            const colIdx = parseInt(colNum, 10);
            if (!colIdx) return;
            const mediaRef = getCellMediaRef(sheet, excelRow, colIdx, rowData[colIdx]);
            if (genIsUrl(mediaRef)) user.imgs[colNum] = mediaRef;
        });

        Object.keys(DEPT_CONTENT_CONFIG).forEach(function(deptName) {
            const cfg = DEPT_CONTENT_CONFIG[deptName];
            const images = [];
            cfg.images.forEach(function(imgCfg) {
                const imgUrl = getCellMediaRef(sheet, excelRow, imgCfg.img, rowData[imgCfg.img]);
                const imgDesc = normalizeCellText(rowData[imgCfg.desc]);
                if (genIsUrl(imgUrl)) {
                    images.push({
                        url: imgUrl,
                        desc: imgDesc,
                        col: imgCfg.img
                    });
                }
            });

            const rawStats1 = normalizeCellText(rowData[cfg.statsCol1]);
            const rawStats2 = normalizeCellText(rowData[cfg.statsCol2]);
            const stats1 = genSmartParseInt(rawStats1);
            const stats2 = cfg.statsCol2Name === '最爱的歌' ? 0 : genSmartParseInt(rawStats2);
            const roleTags = [];

            (cfg.roleOptionCols || []).forEach(function(roleCfg) {
                if (isMarkedChoice(rowData[roleCfg.col])) roleTags.push(roleCfg.label);
            });

            const customRole = normalizeCellText(rowData[cfg.customRoleCol]);
            if (customRole && !['0', '1'].includes(customRole)) roleTags.push(customRole);

            user.deptData[deptName] = {
                stats1: stats1,
                stats1Raw: rawStats1,
                stats1Name: cfg.statsCol1Name,
                stats2: stats2,
                stats2Raw: rawStats2,
                stats2Name: cfg.statsCol2Name,
                images: images,
                roles: roleTags,
                primaryRole: roleTags[0] || ''
            };
        });

        const ipPhoto = getCellMediaRef(sheet, excelRow, COMMON_CONFIG.ipPhotoCol, rowData[COMMON_CONFIG.ipPhotoCol]);
        const memoryPhoto = getCellMediaRef(sheet, excelRow, COMMON_CONFIG.memoryPhotoCol, rowData[COMMON_CONFIG.memoryPhotoCol]);
        const groupPhoto = getCellMediaRef(sheet, excelRow, COMMON_CONFIG.groupPhotoCol, rowData[COMMON_CONFIG.groupPhotoCol]);
        user.commonData = {
            isFreeSpirit: isMarkedChoice(rowData[COMMON_CONFIG.freeSpiritCol]),
            activityCount: activityCount,
            activityLevel: activityLevel,
            activityRaw: activityRaw,
            ip: normalizeCellText(rowData[COMMON_CONFIG.ipCol]),
            ipPhoto: genIsUrl(ipPhoto) ? ipPhoto : '',
            keyword: normalizeCellText(rowData[COMMON_CONFIG.keywordCol]),
            memorableQuote: normalizeCellText(rowData[COMMON_CONFIG.memorableQuoteCol]),
            memoryPhoto: genIsUrl(memoryPhoto) ? memoryPhoto : '',
            memoryDesc: normalizeCellText(rowData[COMMON_CONFIG.memoryDescCol]),
            groupPhoto: genIsUrl(groupPhoto) ? groupPhoto : '',
            groupDesc: normalizeCellText(rowData[COMMON_CONFIG.groupDescCol])
        };

        user.keywords = (user.commonData.keyword || '').split(/[,，、\s]+/).filter(function(k) { return k.trim(); });
        user.keywordReason = user.commonData.memorableQuote;
        user.ip = user.commonData.ip;

        rawData.push(user);
    }
    const cleanData = calculateGlobalStats(rawData);
    GENERATOR_STATE.lastMediaSummary = hydrateDbMediaFromUploadedImages(cleanData);
    return cleanData;
}

function applyReportData(payload) {
    if (!payload || !Array.isArray(payload.db)) return false;
    DB = payload.db;
    WEEKLY_PHOTOS = normalizeWeeklyPhotos(payload.weeklyPhotos);
    GENERATOR_STATE.cleanData = payload.db;
    GENERATOR_STATE.weeklyPhotos = normalizeWeeklyPhotos(payload.weeklyPhotos);

    if (payload.bgm1) {
        GENERATOR_STATE.bgm1 = payload.bgm1;
        applyAudioSource('bgMusic', payload.bgm1);
    }
    if (payload.bgm2) {
        GENERATOR_STATE.bgm2 = payload.bgm2;
        applyAudioSource('fireworkMusic', payload.bgm2);
    }

    const totalEl = document.getElementById('total-counts');
    if (totalEl) totalEl.innerText = DB.length;
    if (!GENERATOR_STATE.parsedName && DB.length > 0) GENERATOR_STATE.parsedName = DB[0].name || '';
    return true;
}

function initializeDataFromUserPayload(payload) {
    if (!payload) return;
    if (Array.isArray(payload)) {
        applyReportData({ db: payload, weeklyPhotos: createEmptyWeeklyPhotos() });
        return;
    }
    if (typeof payload === 'object' && Array.isArray(payload.db)) {
        applyReportData(payload);
    }
}

function sanitizeFileName(name) {
    return String(name || '未命名').replace(/[\\/:*?"<>|]/g, '_').trim() || '未命名';
}



// === 客座模式部门数据处理 ===

function applyGuestDeptSummaryData(deptName) {
    if (!window._youziGuestModeActive) return false;
    if (typeof DB === 'undefined' || !Array.isArray(DB)) return false;

    const deptMembers = DB.filter(function(u) { return u.deptData && u.deptData[deptName]; });
    if (deptMembers.length === 0) return false;

    const stats1Data = deptMembers
        .map(function(u) { return { name: u.name, value: u.deptData[deptName].stats1 || 0 }; })
        .filter(function(v) { return v.value > 0; });
    const stats2Data = deptMembers
        .map(function(u) { return { name: u.name, value: u.deptData[deptName].stats2 || 0 }; })
        .filter(function(v) { return v.value > 0; });

    const stats1Total = stats1Data.reduce(function(sum, item) { return sum + item.value; }, 0);
    const stats2Total = stats2Data.reduce(function(sum, item) { return sum + item.value; }, 0);
    const stats1TopUser = stats1Data.length > 0 ? stats1Data.reduce(function(max, item) { return item.value > max.value ? item : max; }, stats1Data[0]) : null;
    const stats2TopUser = stats2Data.length > 0 ? stats2Data.reduce(function(max, item) { return item.value > max.value ? item : max; }, stats2Data[0]) : null;

    const introModal = document.querySelector('.dept-intro-modal.active');
    if (!introModal) return false;

    const cards = introModal.querySelectorAll('.netease-card');
    let cardIndex = 0;
    cards.forEach(function(card) {
        const numberEl = card.querySelector('.netease-number');
        const titleEl = card.querySelector('.netease-title');
        const descEl = card.querySelector('.netease-desc');
        const labelEl = card.querySelector('.netease-label');
        const statsInfoEl = card.querySelector('.dept-stats-info');

        if (labelEl && labelEl.textContent.indexOf('ENTERING') >= 0) return;
        if (card.querySelector('#enter-dept-btn')) return;

        if (numberEl && cardIndex === 0 && stats1Total > 0) {
            numberEl.textContent = stats1Total;
            if (descEl) descEl.textContent = '部门总计';
            if (statsInfoEl && stats1TopUser) {
                statsInfoEl.innerHTML = '突出贡献: <span class="highlight">' + stats1TopUser.name + '</span> (' + stats1TopUser.value + ')';
            } else if (stats1TopUser) {
                const newInfo = document.createElement('div');
                newInfo.className = 'dept-stats-info';
                newInfo.innerHTML = '突出贡献: <span class="highlight">' + stats1TopUser.name + '</span> (' + stats1TopUser.value + ')';
                card.appendChild(newInfo);
            }
            cardIndex++;
        } else if ((numberEl || titleEl) && cardIndex === 1 && stats2Total > 0) {
            if (numberEl) numberEl.textContent = stats2Total;
            if (titleEl && !numberEl) titleEl.textContent = stats2Total;
            if (descEl) descEl.textContent = '部门总计';
            if (statsInfoEl && stats2TopUser) {
                statsInfoEl.innerHTML = '突出贡献: <span class="highlight">' + stats2TopUser.name + '</span> (' + stats2TopUser.value + ')';
            } else if (stats2TopUser) {
                const newInfo = document.createElement('div');
                newInfo.className = 'dept-stats-info';
                newInfo.innerHTML = '突出贡献: <span class="highlight">' + stats2TopUser.name + '</span> (' + stats2TopUser.value + ')';
                card.appendChild(newInfo);
            }
            cardIndex++;
        }
    });

    return true;
}

function waitApplyGuestDeptSummary(deptName) {
    if (!window._youziGuestModeActive) return;
    let tries = 0;
    const maxTries = 180;
    const tick = function() {
        if (applyGuestDeptSummaryData(deptName)) return;
        tries++;
        if (tries < maxTries) requestAnimationFrame(tick);
    };
    requestAnimationFrame(tick);
}



// ============================================================
// file-io.js - 文件I/O模块 (FileIO)
// Excel解析、图片处理、ZIP导出
// ============================================================

function fileToBase64(file) {
    return new Promise(function(resolve, reject) {
        const reader = new FileReader();
        reader.onload = function(event) {
            const img = new Image();
            img.onload = function() {
                const maxWidth = 1000;
                const maxHeight = 1000;
                const quality = 0.8;
                let width = img.width;
                let height = img.height;
                if (width > height && width > maxWidth) {
                    height = Math.round((height * maxWidth) / width);
                    width = maxWidth;
                } else if (height > maxHeight) {
                    width = Math.round((width * maxHeight) / height);
                    height = maxHeight;
                }
                const canvas = document.createElement('canvas');
                canvas.width = width;
                canvas.height = height;
                const ctx = canvas.getContext('2d');
                ctx.drawImage(img, 0, 0, width, height);
                resolve(canvas.toDataURL('image/jpeg', quality));
            };
            img.onerror = reject;
            img.src = event.target.result;
        };
        reader.onerror = reject;
        reader.readAsDataURL(file);
    });
}

function readAudioAsBase64(file) {
    return new Promise(function(resolve, reject) {
        const reader = new FileReader();
        reader.onload = function(event) { resolve(event.target.result); };
        reader.onerror = reject;
        reader.readAsDataURL(file);
    });
}

function readFileAsDataUrl(file) {
    return new Promise(function(resolve, reject) {
        const reader = new FileReader();
        reader.onload = function(event) { resolve(event.target.result); };
        reader.onerror = reject;
        reader.readAsDataURL(file);
    });
}


function buildExportPayload() {
    const dbData = (Array.isArray(GENERATOR_STATE.cleanData) && GENERATOR_STATE.cleanData.length > 0)
        ? GENERATOR_STATE.cleanData
        : DB;
    return {
        db: dbData,
        weeklyPhotos: normalizeWeeklyPhotos(GENERATOR_STATE.weeklyPhotos),
        bgm1: GENERATOR_STATE.bgm1 || getAudioSource('bgMusic'),
        bgm2: GENERATOR_STATE.bgm2 || getAudioSource('fireworkMusic')
    };
}


async function exportGeneratedHtml() {
    const payload = buildExportPayload();
    if (!Array.isArray(payload.db) || payload.db.length === 0) {
        setGeneratorStatus('请先上传并解析 Excel，再导出。', true);
        return;
    }

    const mediaSummary = hydrateDbMediaFromUploadedImages(payload.db);
    GENERATOR_STATE.lastMediaSummary = mediaSummary;
    if (mediaSummary.unresolved > 0) {
        setGeneratorStatus('导出失败：还有 ' + mediaSummary.unresolved + ' 个图片引用未匹配上传文件，请先上传对应图片目录。', true);
        return;
    }

    // Step 1: 获取完整HTML源代码
    let sourceCode = document.documentElement.outerHTML;

    // Step 2: 检查并替换数据占位区块
    const dataBootstrapPattern = /let USER_DATA = null;\s*[\r\n]+\s*let DB = \[\];\s*[\r\n]+\s*let WEEKLY_PHOTOS = createEmptyWeeklyPhotos\(\);\s*[\r\n]+\s*initializeDataFromUserPayload\(USER_DATA\);\s*/m;
    if (!dataBootstrapPattern.test(sourceCode)) {
        setGeneratorStatus('导出失败：未找到数据注入占位区块。', true);
        return;
    }

    // Step 3: 构建JSON并注入数据
    // ⚠️ 必须转义 </script>，否则注入到 HTML sourceCode 时会截断 <script> 块，
    //    导致 Step 6a 正则提取失败。提取到 script.js 后 <\/script> 仍等价于 </script>。
    const dbJson = JSON.stringify(payload.db).replace(/<\/script>/gi, '<\\/script>');
    const weeklyJson = JSON.stringify(normalizeWeeklyPhotos(payload.weeklyPhotos)).replace(/<\/script>/gi, '<\\/script>');
    sourceCode = sourceCode.replace(dataBootstrapPattern, function() {
        return 'const DB = ' + dbJson + ';\n        const WEEKLY_PHOTOS = ' + weeklyJson + ';\n';
    });

    // Step 4: 注入音频sources
    function escapeAttrValue(value) {
        return String(value || '').replace(/&/g, '&amp;').replace(/"/g, '&quot;');
    }
    const bgm1Src = escapeAttrValue(payload.bgm1 || getAudioSource('bgMusic') || '');
    const bgm2Src = escapeAttrValue(payload.bgm2 || getAudioSource('fireworkMusic') || '');
    sourceCode = sourceCode.replace(/(<audio id="bgMusic"[^>]*>[\s\r\n]*<source[^>]*src=")([^"]*)(")/i, function(_, head, __, tail) {
        return head + bgm1Src + tail;
    });
    sourceCode = sourceCode.replace(/(<audio id="fireworkMusic"[^>]*>[\s\r\n]*<source[^>]*src=")([^"]*)(")/i, function(_, head, __, tail) {
        return head + bgm2Src + tail;
    });

    // Step 5: 移除生成器专用资源和面板
    sourceCode = sourceCode.replace(/\s*<script src="https:\/\/cdn\.jsdelivr\.net\/npm\/xlsx@0\.18\.5\/dist\/xlsx\.full\.min\.js"><\/script>\s*/i, '\n');
    sourceCode = sourceCode.replace(/\s*<script src="https:\/\/cdn\.jsdelivr\.net\/npm\/jszip@[^"]*"><\/script>\s*/i, '\n');
    sourceCode = sourceCode.replace(/<!-- GENERATOR_PANEL_START -->[\s\S]*?<!-- GENERATOR_PANEL_END -->\s*/i, '');
    // 移除运行态注入的看板娘 DOM，避免导出后节点已存在但事件未绑定
    sourceCode = sourceCode.replace(/\s*<div id="ai-mascot-wrap"[\s\S]*?<\/div>\s*<\/div>\s*(?=(?:<script|<\/body>))/i, '\n');

    // Step 6: 拆分为 index.html + style.css + script.js
    const jsBlocks = [];

    // 6a-pre: 获取本地脚本内容并内联（data-local 标记的外部脚本）
    
    const localScriptPattern = /<script\b[^>]*\bdata-local\b[^>]*\bsrc="([^"]+)"[^>]*><\/script>/gi;
    let localMatch;
    let failedScripts = [];
    while ((localMatch = localScriptPattern.exec(sourceCode)) !== null) {
        const src = localMatch[1];
        let text = '';

        
        if (!text && window.__SC && window.__SC[src]) {
            text = window.__SC[src];
        }

        // 方式2: 同步 XMLHttpRequest（HTTP 下可靠，部分 file:// 环境也可用）
        if (!text) {
            try {
                var xhr = new XMLHttpRequest();
                xhr.open('GET', src, false);
                xhr.send();
                if ((xhr.status === 200 || xhr.status === 0) && xhr.responseText) {
                    text = xhr.responseText;
                }
            } catch (e) { /* 静默失败，尝试下一种方式 */ }
        }

        // 方式3: fetch（仅 HTTP/HTTPS 协议可用）
        if (!text) {
            try {
                const resp = await fetch(src);
                text = await resp.text();
            } catch (e) { /* 静默失败 */ }
        }

        if (text && text.trim()) {
            jsBlocks.push(text);
        } else {
            failedScripts.push(src);
        }
    }

    if (failedScripts.length > 0) {
        var isFileProtocol = location.protocol === 'file:';
        var hint = isFileProtocol
            ? '\n\n当前以 file:// 协议打开，浏览器安全策略禁止读取本地文件。\n请使用本地服务器打开此页面后再导出：\n  · VS Code 安装 "Live Server" 插件，右键 generator.html → Open with Live Server\n  · 或在此目录打开终端，运行 python -m http.server 8080，然后浏览器访问 http://localhost:8080/generator.html'
            : '';
        setGeneratorStatus('导出失败：无法读取 ' + failedScripts.length + ' 个模块文件（' + failedScripts.join(', ') + '）。' + hint, true);
        return;
    }

    sourceCode = sourceCode.replace(/<script\b[^>]*\bdata-local\b[^>]*><\/script>/gi, '');

    // 6a: 提取所有内联 <script> 内容（保留 CDN <script src> 不动）
    sourceCode = sourceCode.replace(/<script(?![^>]*\bsrc=)[^>]*>([\s\S]*?)<\/script>/gi, function(match, content) {
        if (!content.trim()) return '';
        // 过滤 Live Server / 开发工具注入的脚本（含 WebSocket 连接）
        if (/new\s+WebSocket\b/.test(content)) return '';
        jsBlocks.push(content);
        return '';
    });
    // 在 </body> 前插入外联脚本引用
    sourceCode = sourceCode.replace(/<\/body>/i, '    <script src="script.js"><\/script>\n</body>');

    // 6b: 提取所有 <style> 内容（此时 <script> 已移除，不会误匹配模板中的 <style>）
    const cssBlocks = [];
    sourceCode = sourceCode.replace(/<style[^>]*>([\s\S]*?)<\/style>/gi, function(match, content) {
        if (content.trim()) cssBlocks.push(content.trim());
        return '';
    });
    // 在 </head> 前插入外联样式引用
    sourceCode = sourceCode.replace(/<\/head>/i, '    <link rel="stylesheet" href="style.css">\n</head>');

    const cssContent = cssBlocks.join('\n\n');
    
    var jsRaw = jsBlocks.join('\n\n');
    const jsContent = jsRaw.replace(/\n?\/\/[^\n]*(?:缓存|__SC)[^\n]*\n/g, '\n').replace(/;?\(function\(\)\{try\{var s=document\.currentScript,x=new XMLHttpRequest\(\);x\.open\('GET',s\.src,false\);x\.send\(\);if\(x\.responseText\)\(window\.__SC=window\.__SC\|\|\{\}\)\[s\.getAttribute\('src'\)\]=x\.responseText\}catch\(e\)\{\}\}\)\(\);?/g, '');
    const indexContent = '<!DOCTYPE html>\n' + sourceCode;

    // Step 7: 打包为 ZIP 并下载
    const exportName = sanitizeFileName(GENERATOR_STATE.parsedName || payload.db[0].name || '未命名');
    const folderName = '2025年度总结_' + exportName;

    if (typeof JSZip === 'undefined') {
        setGeneratorStatus('导出失败：JSZip 库未加载，无法生成 ZIP。', true);
        return;
    }

    setGeneratorStatus('正在生成 ZIP 文件…', false);

    const zip = new JSZip();
    const folder = zip.folder(folderName);
    folder.file('index.html', indexContent);
    folder.file('style.css', cssContent);
    folder.file('script.js', jsContent);

    // 打包看板娘表情素材到 assets/ 文件夹
    var mascotAssets = ['Normal.png', 'Happy.png', 'Surprised.png', 'Thinking.png', 'Sad.png', 'Victory.png'];
    var assetsFolder = folder.folder('assets');
    await Promise.all(mascotAssets.map(function(name) {
        return fetch('assets/' + name)
            .then(function(resp) { return resp.ok ? resp.blob() : null; })
            .then(function(blob) { if (blob) assetsFolder.file(name, blob); })
            .catch(function() { /* asset not found, skip */ });
    }));

    try {
        var blob = await zip.generateAsync({ type: 'blob' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = folderName + '.zip';
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
        setGeneratorStatus('导出成功：' + folderName + '.zip（含 index.html + style.css + script.js + assets/）', false);
    } catch (err) {
        setGeneratorStatus('导出失败：ZIP 生成错误 - ' + err.message, true);
    }
}

async function handlePhotoDirectory(files) {
    const mapped = createEmptyWeeklyPhotos();
    const list = Array.from(files || []);
    const uploadedImageMap = new Map();
    let processed = 0;
    let weeklyMatched = 0;
    for (let i = 0; i < list.length; i++) {
        const file = list[i];
        const mime = (file && file.type) ? String(file.type) : '';
        const isImage = /^image\//i.test(mime);
        const isVideo = /^video\//i.test(mime);
        if (!file || (!isImage && !isVideo)) continue;
        const refPath = file.webkitRelativePath || file.name;
        try {
            const base64 = isImage ? await fileToBase64(file) : await readFileAsDataUrl(file);
            addUploadedImageToMap(uploadedImageMap, refPath, base64);
            const dept = detectDeptByPath(refPath);
            if (dept && isImage) {
                mapped[dept].push(base64);
                weeklyMatched++;
            }
        } catch (e) {
            console.warn('Photo convert failed:', file.name, e);
        }
        processed++;
        if (processed % 5 === 0) {
            setGeneratorStatus('周常照片处理中：' + processed + '/' + list.length, false);
            updatePhotoStatsText(mapped);
        }
    }

    GENERATOR_STATE.uploadedImageMap = uploadedImageMap;
    GENERATOR_STATE.weeklyPhotos = normalizeWeeklyPhotos(mapped);
    WEEKLY_PHOTOS = normalizeWeeklyPhotos(mapped);
    updatePhotoStatsText(mapped);

    let mediaTip = '';
    if (Array.isArray(GENERATOR_STATE.cleanData) && GENERATOR_STATE.cleanData.length > 0) {
        const mediaSummary = hydrateDbMediaFromUploadedImages(GENERATOR_STATE.cleanData);
        GENERATOR_STATE.lastMediaSummary = mediaSummary;
        applyReportData({
            db: GENERATOR_STATE.cleanData,
            weeklyPhotos: GENERATOR_STATE.weeklyPhotos,
            bgm1: GENERATOR_STATE.bgm1,
            bgm2: GENERATOR_STATE.bgm2
        });
        mediaTip = '；Excel图片回填 ' + mediaSummary.replaced + ' 项';
        if (mediaSummary.unresolved > 0) mediaTip += '，未匹配 ' + mediaSummary.unresolved + ' 项';
    }

    setGeneratorStatus('照片解析完成：处理 ' + processed + ' 张，周常归类 ' + weeklyMatched + ' 张' + mediaTip + '。', false);
}




// ============================================================
// generator-ui.js - 生成器UI模块
// 面板事件绑定、状态显示
// ============================================================

function setGeneratorStatus(text, isError) {
    const el = document.getElementById('generator-status');
    if (!el) return;
    el.textContent = text;
    el.style.color = isError ? '#ff9191' : '#9cd7ff';
}

function updatePhotoStatsText(photos) {
    const statsEl = document.getElementById('photo-stats');
    if (!statsEl) return;
    const map = photos || createEmptyWeeklyPhotos();
    const lines = [
        'COS: ' + (map['COS部'] || []).length,
        '技术: ' + (map['技术部'] || []).length,
        '轻音: ' + (map['轻音部'] || []).length,
        '原创: ' + (map['原创部'] || []).length,
        '舞: ' + (map['舞装部'] || []).length,
        '外宣: ' + (map['外宣部'] || []).length
    ];
    statsEl.value = lines.join(', ');
}

async function handleGeneratorExportClick(btn) {
    const exportBtn = btn || document.getElementById('btn-export');
    if (exportBtn && exportBtn.dataset.exporting === '1') return;

    setGeneratorStatus('正在生成报告，请稍候…', false);

    if (typeof exportGeneratedHtml !== 'function') {
        setGeneratorStatus('导出失败：导出模块未加载。', true);
        return;
    }

    const originalText = exportBtn ? exportBtn.textContent : '';
    try {
        if (exportBtn) {
            exportBtn.dataset.exporting = '1';
            exportBtn.disabled = true;
            exportBtn.textContent = '⏳ 生成中...';
            exportBtn.style.opacity = '0.7';
            exportBtn.style.cursor = 'wait';
        }
        await exportGeneratedHtml();
    } catch (err) {
        console.error(err);
        setGeneratorStatus('导出失败：' + (err && err.message ? err.message : err), true);
    } finally {
        if (exportBtn) {
            exportBtn.dataset.exporting = '0';
            exportBtn.disabled = false;
            exportBtn.textContent = originalText || '🚀 导出最终 HTML 报告';
            exportBtn.style.opacity = '';
            exportBtn.style.cursor = '';
        }
    }
}

function bindGeneratorPanelEvents() {
    const panel = document.getElementById('generator-panel');
    if (!panel) return;

    const excelInput = document.getElementById('excel-file');
    const photoInput = document.getElementById('photo-dir');
    const bgm1Input = document.getElementById('bgm1-file');
    const bgm2Input = document.getElementById('bgm2-file');
    const exportBtn = document.getElementById('btn-export');
    const exportRow = document.getElementById('export-action-row');

    updatePhotoStatsText(GENERATOR_STATE.weeklyPhotos);

    if (excelInput) {
        excelInput.addEventListener('change', async function(e) {
            const file = e.target.files && e.target.files[0];
            if (!file) return;
            setGeneratorStatus('Excel 解析中：' + file.name, false);
            try {
                const cleanData = await parseExcelFile(file);
                GENERATOR_STATE.cleanData = cleanData;
                GENERATOR_STATE.parsedName = cleanData[0] ? (cleanData[0].name || '') : '';
                applyReportData({
                    db: cleanData,
                    weeklyPhotos: GENERATOR_STATE.weeklyPhotos,
                    bgm1: GENERATOR_STATE.bgm1,
                    bgm2: GENERATOR_STATE.bgm2
                });
                const mediaSummary = GENERATOR_STATE.lastMediaSummary || { replaced: 0, unresolved: 0 };
                let mediaTip = '；图片内嵌 ' + mediaSummary.replaced + ' 项';
                if (mediaSummary.unresolved > 0) mediaTip += '，未匹配 ' + mediaSummary.unresolved + ' 项';
                setGeneratorStatus('Excel 解析完成，共 ' + cleanData.length + ' 人' + mediaTip + '。', false);
            } catch (err) {
                console.error(err);
                setGeneratorStatus('Excel 解析失败：' + err.message, true);
            }
        });
    }

    if (photoInput) {
        photoInput.addEventListener('change', async function(e) {
            const files = e.target.files;
            if (!files || files.length === 0) return;
            setGeneratorStatus('周常照片读取中：' + files.length + ' 个文件', false);
            await handlePhotoDirectory(files);
        });
    }

    if (bgm1Input) {
        bgm1Input.addEventListener('change', async function(e) {
            const file = e.target.files && e.target.files[0];
            if (!file) return;
            try {
                GENERATOR_STATE.bgm1 = await readAudioAsBase64(file);
                applyAudioSource('bgMusic', GENERATOR_STATE.bgm1);
                setGeneratorStatus('BGM1 已载入：' + file.name, false);
            } catch (err) {
                setGeneratorStatus('BGM1 读取失败：' + err.message, true);
            }
        });
    }

    if (bgm2Input) {
        bgm2Input.addEventListener('change', async function(e) {
            const file = e.target.files && e.target.files[0];
            if (!file) return;
            try {
                GENERATOR_STATE.bgm2 = await readAudioAsBase64(file);
                applyAudioSource('fireworkMusic', GENERATOR_STATE.bgm2);
                setGeneratorStatus('BGM2 已载入：' + file.name, false);
            } catch (err) {
                setGeneratorStatus('BGM2 读取失败：' + err.message, true);
            }
        });
    }

    if (exportBtn && exportBtn.dataset.bound !== '1') {
        exportBtn.dataset.bound = '1';
        exportBtn.onclick = function() { handleGeneratorExportClick(exportBtn); };
    }

    if (exportRow && exportRow.dataset.bound !== '1') {
        exportRow.dataset.bound = '1';
        exportRow.addEventListener('keydown', function(e) {
            if (e.key === 'Enter' || e.key === ' ') {
                e.preventDefault();
                handleGeneratorExportClick(exportBtn);
            }
        });
    }
}





// ============================================================
// components/dept-renderers.js - 部门页面渲染组件
// 从 generator.html 提取
// 包含: renderDeptGrid, showDeptIntro, renderWeeklyPhotos,
//       openPhotoModal, closePhotoModal,
//       renderCosDept, renderTechDept, renderMusicDept,
//       renderDanceDept, renderArtDept, renderPrDept
// 依赖全局: DB, currentUser, DEPARTMENTS, WEEKLY_PHOTOS,
//           DEPT_ID_TO_NAME, deptClickGuardUntil,
//           calculateDeptAverage, renderWeeklyPhotos,
//           initScrollAnimation, initInfluenceDashboardAnimation,
//           initPrDeptNarrative, renderInfluenceDashboard
// ============================================================
function renderDeptGrid(deptId, deptName, otherImages, isInDept, deptMembers, myImages) {
    try {
    let html = '';
    switch(deptId) {
        case 'cos': html = renderCosDept(deptName, otherImages, isInDept, deptMembers, myImages); break;
        case 'tech': html = renderTechDept(deptName, otherImages, isInDept, deptMembers, myImages); break;
        case 'music': html = renderMusicDept(deptName, otherImages, isInDept, deptMembers, myImages); break;
        case 'dance': html = renderDanceDept(deptName, otherImages, isInDept, deptMembers, myImages); break;
        case 'art': html = renderArtDept(deptName, otherImages, isInDept, deptMembers, myImages); break;
        case 'pr': html = renderPrDept(deptName, otherImages, isInDept, deptMembers, myImages); break;
    }
    document.getElementById('dept-content').innerHTML = html;

    // 启动滚动动画 (所有部门通用)
    requestAnimationFrame(() => {
        if (window.initScrollAnimation) window.initScrollAnimation();
        
        if (deptId === 'pr') {
            // 如果是外宣部，启动影响力看板动画
            initInfluenceDashboardAnimation();
            // 外宣顶部叙事：随滚动复现 + 点击跳转
            initPrDeptNarrative();
        }
    });
    } catch(e) {
        console.error('[renderDeptGrid ERROR]', e);
        alert('渲染部门内容时出错: ' + e.message);
    }
}

// New Intro Slide Logic
// New Intro Slide Logic - Swiper Version
function showDeptIntro(deptId, myData, myImages, onComplete) {
    // Create container
    let modal = document.querySelector('.dept-intro-modal');
    if (modal) modal.remove();
    
    modal = document.createElement('div');
    modal.className = 'dept-intro-modal active';
    modal.setAttribute('data-dept', deptId);
    document.body.appendChild(modal);
    
    // Build Slides Data
    const slides = [];
    
    // Helper to add slide
    const addSlide = (content) => {
        slides.push('<div class="swiper-slide"><div class="intro-slide-content" style="width:100%;height:100%;display:flex;flex-direction:column;align-items:center;justify-content:center;">' + content + '</div></div>');
    };

    // Slide 1: Welcome / Title
    // 使用 Netease 风格的卡片布局
    addSlide(`
        <div class="netease-card">
            <div class="netease-label" style="color:var(--accent-blue)">ENTERING SYSTEM</div>
            <div class="netease-number" style="font-size: clamp(32px, 8vw, 48px);">${DEPT_ID_TO_NAME[deptId]}</div>
            <div class="netease-desc">从这里开始，逐步查看你的年度画像</div>
            <div class="netease-scroll-hint">向下滑动查看更多</div>
        </div>
    `);
    
    const deptFullName = DEPT_ID_TO_NAME[deptId];
    const isYouziGuestMode = window._youziGuestModeActive === true;
    const titles = {
        cos: { dim1: '平行人生', dim2: '高光瞬间' },
        tech: { dim1: '时光捕手', dim2: '星夜兼程' },
        music: { dim1: '心流时刻', dim2: '灵魂共振' },
        dance: { dim1: '身体记忆', dim2: '挥洒热忱' },
        art: { dim1: '绘梦记录', dim2: '在此诞生' },
        pr: { dim1: '异世界漫游', dim2: '奔赴热爱' }
    };
    const copyStyleNetease = {
        cos: {
            1: (d) => `这一年，你一共走进了 ${d.value} 个角色的世界。每一次变身，都是一次与二次元的久别重逢。`,
            2: (d) => `镜头捕捉了你的光芒，${d.value}${d.keywordSuffix}返图，定格了那些闪闪发光的瞬间。`
        },
        tech: {
            1: (d) => `你习惯躲在取景器后，用 ${d.value}${d.keywordSuffix}的记录，默默守护着大家的珍贵回忆。`,
            2: (d) => `那个 ${d.value} 的深夜，屏幕的光映在脸上，你还在为心中完美的画面修修补补。`
        },
        music: {
            1: (d) => `排练室的墙壁听过你的心跳。这 ${d.value}${d.keywordSuffix}的沉浸，终将变成舞台上的惊艳。`,
            2: (d) => `「${d.value}」是你今年的年度羁绊。无论开心还是难过，只有这首歌最懂你的心事。`
        },
        dance: {
            1: (d) => `身体比语言更诚实。${d.value}${d.keywordSuffix}新动作的背后，是无数次摔倒又站起的坚持。`,
            2: (d) => `为了那几分钟的绽放，你挥洒了 ${d.value}${d.keywordSuffix}的汗水。地板记得你所有的努力。`
        },
        art: {
            1: (d) => `这一年，你笔下诞生了 ${d.value}${d.keywordSuffix}绚丽的世界。是你让想象力有了具体的形状。`,
            2: (d) => `你赋予了 ${d.value}${d.keywordSuffix}原创角色灵魂。对他们来说，你就是创造宇宙的神明。`
        },
        pr: {
            1: (d) => `你在 ${d.value} 部番剧里流连忘返。那些热血与感动，一定也温暖了现实中的你。`,
            2: (d) => `热爱就是要见面。${d.value}${d.keywordSuffix}线下奔赴，让“同好”这个词有了真实的温度。`
        },
        default: {
            1: (d) => `时光流转，你在 ${d.deptName} 留下了 ${d.value}${d.keywordSuffix}足迹。`,
            2: (d) => `回望过去，这是属于你在 ${d.deptName} 的 ${d.value}${d.keywordSuffix}独家记忆。`
        }
    };
    const titleSet = titles[deptId] || { dim1: '年度片段', dim2: '独家记忆' };
    const makeKeywordSuffix = (keywordText) => keywordText ? ('（' + keywordText + '）') : '';
    const buildDeptIntroDesc = (dimension, mode, valueText, topName, keywordText) => {
        if (mode === 'guest') {
            const topText = topName ? ('，最高记录来自' + topName + '。') : '。';
            const section = dimension === 1 ? titleSet.dim1 : titleSet.dim2;
            return '今年' + deptFullName + '在「' + section + '」里累计留下了' + String(valueText) + '份记录' + topText;
        }
        const deptCopy = copyStyleNetease[deptId] || copyStyleNetease.default;
        const renderer = deptCopy[dimension] || copyStyleNetease.default[dimension];
        return renderer({
            deptName: deptFullName,
            value: String(valueText),
            keywordSuffix: makeKeywordSuffix(keywordText || '')
        });
    };
    
    // 收集该部门所有成员的数据用于统计
    const deptMembers = DB.filter(u => u.deptData && u.deptData[deptFullName]);
    
    // 计算stats1的统计数据（平均值、最大值）
    const stats1Data = deptMembers
        .map(u => ({ name: u.name, value: u.deptData[deptFullName].stats1 || 0 }))
        .filter(item => item.value > 0);
    const stats1Avg = stats1Data.length > 0 ? Math.round(stats1Data.reduce((sum, item) => sum + item.value, 0) / stats1Data.length) : 0;
    const stats1Max = stats1Data.length > 0 ? stats1Data.reduce((max, item) => item.value > max.value ? item : max, stats1Data[0]) : null;
    
    // 计算stats2的统计数据（平均值、最大值）- 轻音部除外（因为是文本）
    const stats2Data = deptId !== 'music' ? deptMembers
        .map(u => ({ name: u.name, value: u.deptData[deptFullName].stats2 || 0 }))
        .filter(item => item.value > 0) : [];
    const stats2Avg = stats2Data.length > 0 ? Math.round(stats2Data.reduce((sum, item) => sum + item.value, 0) / stats2Data.length) : 0;
    const stats2Max = stats2Data.length > 0 ? stats2Data.reduce((max, item) => item.value > max.value ? item : max, stats2Data[0]) : null;
    const stats1Total = stats1Data.length > 0 ? stats1Data.reduce((sum, item) => sum + item.value, 0) : 0;
    const stats2Total = stats2Data.length > 0 ? stats2Data.reduce((sum, item) => sum + item.value, 0) : 0;
    const musicSongItems = deptId === 'music'
        ? DB.filter(u => u.deptData && u.deptData['轻音部'] && u.deptData['轻音部'].stats2Raw)
            .map(u => ({ name: u.name, song: u.deptData['轻音部'].stats2Raw }))
            .filter(item => item.song && item.song.trim() !== '' && item.song.trim() !== '0')
        : [];
    let musicTopAuthor = '';
    if (musicSongItems.length > 0) {
        const authorCount = {};
        musicSongItems.forEach(function(item) {
            authorCount[item.name] = (authorCount[item.name] || 0) + 1;
        });
        musicTopAuthor = Object.keys(authorCount).sort(function(a, b) {
            return authorCount[b] - authorCount[a];
        })[0] || '';
    }
    
    // 辅助函数：判断是否有有效数据（数字>0 或 非空文本）
    const hasValidData = (numVal, rawVal) => {
        if (numVal > 0) return true;
        if (rawVal && String(rawVal).trim() !== '' && String(rawVal).trim() !== '0') return true;
        return false;
    };
    
    // 辅助函数：获取显示值（优先数字，否则显示原始文本）
    const getDisplayValue = (numVal, rawVal) => {
        if (numVal > 0) return numVal;
        if (rawVal && String(rawVal).trim() !== '') return String(rawVal).trim();
        return '';
    };
    
    // Slide 2: Question 1
    const stats1Display = isYouziGuestMode
        ? (stats1Total > 0 ? stats1Total : '')
        : getDisplayValue(myData?.stats1, myData?.stats1Raw);
    if (stats1Display) {
        const isNum = typeof stats1Display === 'number';
        // 构建部门统计信息
        let stats1Info = '';
        if (!isYouziGuestMode && stats1Avg > 0 && stats1Max) {
            stats1Info = `<div class="dept-stats-info">部门成员平均: <span class="highlight">${stats1Avg}</span> | 最高: <span class="highlight">${stats1Max.name}</span> (${stats1Max.value})</div>`;
        }
        const stats1Desc = buildDeptIntroDesc(
            1,
            isYouziGuestMode ? 'guest' : 'self',
            stats1Display,
            isYouziGuestMode && stats1Max ? stats1Max.name : '',
            !isYouziGuestMode ? (myData?.stats1Name || '') : ''
        );
        const stats1Label = isYouziGuestMode ? ('今年' + deptFullName + ' · ' + titleSet.dim1) : ('你的年度故事 · ' + titleSet.dim1);
        addSlide(`
            <div class="netease-card">
                <div class="netease-label">${stats1Label}</div>
                <div class="${isNum ? 'netease-number' : 'netease-title'}" style="${!isNum ? 'font-size:clamp(28px, 6vw, 48px); margin:30px 0;' : ''}">${stats1Display}</div>
                <div class="netease-desc">${stats1Desc}</div>
                ${stats1Info}
            </div>
        `);
    }
    
    // Slide 3: Question 2 - 轻音部特殊处理（显示弹幕）
    const stats2Display = isYouziGuestMode
        ? (deptId === 'music' ? (musicSongItems.length > 0 ? musicSongItems.length : '') : (stats2Total > 0 ? stats2Total : ''))
        : getDisplayValue(myData?.stats2, myData?.stats2Raw);
    if (stats2Display) {
        const isNum = typeof stats2Display === 'number';
        
        // 轻音部：显示所有人喜欢的歌曲弹幕
        if (deptId === 'music') {
            const allSongs = musicSongItems;
            const musicDesc = buildDeptIntroDesc(
                2,
                isYouziGuestMode ? 'guest' : 'self',
                stats2Display,
                isYouziGuestMode ? (musicTopAuthor || '') : '',
                ''
            );
            const stats2Label = isYouziGuestMode ? ('今年' + deptFullName + ' · ' + titleSet.dim2) : ('你的年度故事 · ' + titleSet.dim2);
            
            slides.push(`<div class="swiper-slide danmaku-slide"><div class="intro-slide-content" style="width:100%;height:100%;display:flex;flex-direction:column;align-items:center;justify-content:center;">
                <div class="danmaku-bg-container">
                    ${allSongs.map((item, i) => `
                        <div class="danmaku-bg-item" data-trigger-type="contribution" data-contributor="${item.name}" style="animation-delay: ${(i * 0.7) % 9}s; top: ${5 + (i * 12) % 85}%; right: -300px;">
                            <span class="danmaku-name">${item.name}</span>：${item.song}
                        </div>
                    `).join('')}
                </div>
                <div class="netease-card">
                    <div class="netease-label">${stats2Label}</div>
                    <div class="netease-title" style="font-size:clamp(28px, 6vw, 48px); margin:30px 0;">${stats2Display}</div>
                    <div class="netease-desc">${musicDesc}</div>
                </div>
            </div></div>`);
        } else {
            // 构建部门统计信息（非轻音部）
            let stats2Info = '';
            if (!isYouziGuestMode && stats2Avg > 0 && stats2Max) {
                stats2Info = `<div class="dept-stats-info">部门成员平均: <span class="highlight">${stats2Avg}</span> | 最高: <span class="highlight">${stats2Max.name}</span> (${stats2Max.value})</div>`;
            }
            const stats2Desc = buildDeptIntroDesc(
                2,
                isYouziGuestMode ? 'guest' : 'self',
                stats2Display,
                isYouziGuestMode && stats2Max ? stats2Max.name : '',
                !isYouziGuestMode ? (myData?.stats2Name || '') : ''
            );
            const stats2Label = isYouziGuestMode ? ('今年' + deptFullName + ' · ' + titleSet.dim2) : ('你的年度故事 · ' + titleSet.dim2);
            addSlide(`
                <div class="netease-card">
                    <div class="netease-label">${stats2Label}</div>
                    <div class="netease-number" style="${!isNum ? 'font-size:clamp(28px, 6vw, 48px); margin:30px 0;' : ''}">${stats2Display}</div>
                    <div class="netease-desc">${stats2Desc}</div>
                    ${stats2Info}
                </div>
            `);
        }
    }
    
    // Slides: Photos
    if (myImages && myImages.length > 0) {
        myImages.slice(0, 3).forEach(img => {
            // 根据URL判断是视频还是图片，并转义URL防止破坏HTML
            const safeUrl = String(img.url || '').replace(/"/g, '&quot;');
            let mediaHtml;
            if (isVideoUrl(img.url)) {
                mediaHtml = '<video src="' + safeUrl + '" style="max-width:90vw; max-height:60vh; border-radius:10px; box-shadow:0 10px 30px rgba(0,0,0,0.5); object-fit:contain;" controls muted playsinline preload="metadata"></video>';
            } else {
                mediaHtml = '<img src="' + safeUrl + '" style="max-width:90vw; max-height:60vh; border-radius:10px; box-shadow:0 10px 30px rgba(0,0,0,0.5); object-fit:contain;">';
            }
            addSlide(`
                <div class="netease-card" style="padding:0; overflow:hidden; background:none; max-width:800px;" data-trigger-type="contribution" data-contributor="${String(img.author || '').replace(/"/g, '&quot;')}">
                    <div style="position:relative; width:100%; height:100%; display:flex; flex-direction:column; align-items:center;">
                        ${mediaHtml}
                        <div class="netease-desc" style="margin-top:20px;">${img.desc || '精彩瞬间'}</div>
                    </div>
                </div>
            `);
        });
    }
    
    // 如果没有任何数据，显示提示
    const hasAnyStats = stats1Display || stats2Display;
    if (!hasAnyStats && (!myImages || myImages.length === 0)) {
        addSlide(`
            <div class="netease-card">
                <div class="netease-label" style="color: rgba(255,255,255,0.5)">暂无个人数据</div>
                <div class="netease-title" style="font-size: 24px; margin: 20px 0;">你还没有在问卷中填写此部门的数据</div>
                <div class="netease-desc" style="opacity: 0.6;">但你依然可以浏览部门空间~</div>
            </div>
        `);
    }
    
    // Final Slide: Enter
    addSlide(`
        <div class="netease-card">
            <div class="netease-title" style="font-size:32px; margin-bottom:30px;">ACCESS GRANTED</div>
            <button class="glass-btn" id="enter-dept-btn" style="pointer-events:auto; font-size:18px; padding:15px 40px;">进入部门空间 <span class="btn-arrow">→</span></button>
        </div>
    `);

    // Inject HTML
    modal.innerHTML = `
        <div class="swiper dept-swiper" style="width:100%; height:100%;">
            <div class="swiper-wrapper">
                ${slides.join('')}
            </div>
            <div class="swiper-pagination"></div>
        </div>
    `;
    
    // Init Swiper
    const swiper = new Swiper('.dept-swiper', {
        direction: 'vertical',
        mousewheel: true,
        pagination: {
            el: '.swiper-pagination',
            clickable: true,
        },
        effect: 'fade',
        fadeEffect: { crossFade: true },
        speed: 600,
    });
    
    // Bind Enter Button
    setTimeout(() => {
        const btn = document.getElementById('enter-dept-btn');
        if(btn) {
            btn.onclick = () => {
                modal.classList.remove('active');
                setTimeout(() => {
                    modal.remove();
                    if (onComplete) onComplete();
                }, 500);
            };
        }
    }, 100);
}


function backFromDept() {
    // Remove intro modal if exists
    const modal = document.querySelector('.dept-intro-modal');
    if (modal) modal.remove();

    // 标记当前部门已访问
    if (currentVisitingDept) {
        visitedDepts.add(currentVisitingDept);
        updateProgressBar();
        // Check if this was the PR dept and if there was a dynamically added overlay
        if (currentVisitingDept === 'pr') {
           const prOverlay = document.querySelector('.dept-summary-overlay');
           if (prOverlay && prOverlay.parentNode) {
               // Ensure clean removal if needed, though innerHTML overwrite does this
           }
        }
        currentVisitingDept = null;
    }
    document.body.classList.remove('phase-dept');
    document.body.classList.remove('phase-report'); // Ensure report mode is off
    document.getElementById('dept-content').innerHTML = ''; // Clean up DOM
    starshipObj.returnToOrbit();
}

// 初始化进度条星球点击事件
function initProgressPlanetClicks() {
    document.querySelectorAll('.planet-dot').forEach(dot => {
        if (dot.dataset.youziBound === '1') return;
        dot.dataset.youziBound = '1';
        dot.addEventListener('click', (e) => {
            e.stopPropagation();
            const deptId = dot.dataset.dept;
            const index = parseInt(dot.dataset.index);
            if (!isNaN(index) && starshipObj) {
                // 飞向对应星球
                starshipObj.goToPlanet(index);
            }
        });
    });
}

function goToPlanetByIndex(index) {
    if (typeof index !== 'number' || isNaN(index) || index < 0) return false;
    if (!starshipObj || typeof starshipObj.goToPlanet !== 'function') return false;
    if (index >= DEPARTMENTS.length) return false;
    const now = Date.now();
    if (index === lastPlanetNavIndex && (now - lastPlanetNavAt) < 900) return true;
    lastPlanetNavIndex = index;
    lastPlanetNavAt = now;
    starshipObj.goToPlanet(index);
    return true;
}
if (typeof window !== 'undefined') window.goToPlanetByIndex = goToPlanetByIndex;

function ensureSystemInteractionFallback() {
    const systemLayer = document.getElementById('system-layer');
    if (systemLayer) systemLayer.style.pointerEvents = 'auto';
    const progressPanel = document.getElementById('progress-panel');
    if (progressPanel) progressPanel.style.pointerEvents = 'auto';
    const labelsContainer = document.getElementById('labels-container');
    if (labelsContainer) labelsContainer.style.pointerEvents = 'auto';

    const sunCard = document.getElementById('sun-card');
    if (sunCard) sunCard.style.cursor = 'pointer';

    document.querySelectorAll('.planet-dot').forEach(dot => {
        dot.style.pointerEvents = 'auto';
        dot.style.cursor = 'pointer';
        if (dot.dataset.fallbackBound === '1') return;
        dot.dataset.fallbackBound = '1';
        dot.addEventListener('click', function(e) {
            e.stopPropagation();
            const idx = parseInt(this.dataset.index, 10);
            goToPlanetByIndex(idx);
        }, true);
    });

    document.querySelectorAll('#labels-container .star-card').forEach(card => {
        card.style.pointerEvents = 'auto';
        card.style.cursor = 'pointer';
        if (card.dataset.fallbackBound === '1') return;
        card.dataset.fallbackBound = '1';
        card.addEventListener('click', function(e) {
            e.stopPropagation();
            const idx = parseInt(this.dataset.deptIndex, 10);
            if (!goToPlanetByIndex(idx)) {
                const deptId = this.dataset.deptId || '';
                const resolved = DEPARTMENTS.findIndex(function(d) { return d.id === deptId; });
                goToPlanetByIndex(resolved);
            }
        }, true);
    });

    if (window.__systemGlobalFallbackBound) return;
    window.__systemGlobalFallbackBound = true;

    window.addEventListener('click', function(e) {
        if (!document.body.classList.contains('phase-system')) return;
        if (document.body.classList.contains('phase-dept') || document.body.classList.contains('phase-report')) return;

        const dotTarget = e.target.closest('.planet-dot');
        if (dotTarget) {
            const idx = parseInt(dotTarget.dataset.index, 10);
            goToPlanetByIndex(idx);
            return;
        }

        const cardTarget = e.target.closest('.star-card');
        if (cardTarget) {
            const idx = parseInt(cardTarget.dataset.deptIndex, 10);
            if (!goToPlanetByIndex(idx)) {
                const deptId = cardTarget.dataset.deptId || '';
                const resolved = DEPARTMENTS.findIndex(function(d) { return d.id === deptId; });
                goToPlanetByIndex(resolved);
            }
            return;
        }

        if (e.target.closest('#sun-card')) {
            showReport();
            return;
        }

        if (!raycaster || !camera || !interactables || interactables.length === 0) return;
        if (!mouse && typeof THREE !== 'undefined') mouse = new THREE.Vector2();
        if (!mouse) return;

        mouse.x = (e.clientX / window.innerWidth) * 2 - 1;
        mouse.y = -(e.clientY / window.innerHeight) * 2 + 1;
        raycaster.setFromCamera(mouse, camera);

        if (hubMesh) {
            const sunHits = raycaster.intersectObject(hubMesh);
            if (sunHits.length > 0) {
                showReport();
                return;
            }
        }

        const planetHits = raycaster.intersectObjects(interactables);
        if (planetHits.length > 0) {
            const hit = planetHits[0].object;
            const deptId = hit && hit.userData ? hit.userData.id : '';
            const idx = DEPARTMENTS.findIndex(function(d) { return d.id === deptId; });
            goToPlanetByIndex(idx);
        }
    }, true);
}

// 更新进度条
function updateProgressBar() {
    const count = visitedDepts.size;
    
    // 更新计数
    const countEl = document.getElementById('progress-count');
    if (countEl) countEl.textContent = count;
    
    // 更新星球点状态
    visitedDepts.forEach(deptId => {
        const dot = document.querySelector(`.planet-dot[data-dept="${deptId}"]`);
        if (dot) dot.classList.add('visited');
    });
    
    // 更新提示文字
    const hint = document.getElementById('progress-hint');
    const sunCard = document.getElementById('sun-card');
    if (hint) {
        if (count >= 6) {
            hint.textContent = '探索完成 · 恒星已点亮';
            hint.classList.add('complete');
            // 解锁太阳卡片
            if (sunCard) {
                sunCard.classList.remove('locked');
                sunCard.querySelector('.card-data').textContent = '点击进入恒星报告';
                sunCard.querySelector('.card-body').style.animation = 'sunCardPulse 1.5s ease-in-out infinite';
            }
        } else {
            hint.textContent = '你还差 ' + (6 - count) + ' 颗星球 · 恒星报告待解锁';
            hint.classList.remove('complete');
        }
    }
}

